sql:
SELECT COUNT(*) 
FROM memory_allocations 
WHERE allocation_status = 'active';

SELECT peripheral_name, SUM(size_kb) AS total_size_kb
FROM peripherals
GROUP BY peripheral_name;

SELECT COUNT(*) 
FROM technical_manuals
WHERE INSTR(manual_name, 'Advanced') > 0;

SELECT SUM(al.size_kb) AS total_memory_allocated_kb
FROM peripherals p
INNER JOIN memory_allocations al ON p.peripheral_id = al.peripheral_id;

SELECT mcu_name, mcu_description
FROM mcus
ORDER BY release_date DESC;

SELECT peripheral_id, MAX(size_kb) AS max_memory_allocation_kb
FROM memory_allocations
GROUP BY peripheral_id;

